import{_ as n}from"./plugin-vue_export-helper-c27b6911.js";import{o as a,c as s,e}from"./app-f7c48904.js";const p={},t=e(`<h1 id="有关js函数读取传入对象属性值时-形参与实参所带来的问题" tabindex="-1"><a class="header-anchor" href="#有关js函数读取传入对象属性值时-形参与实参所带来的问题" aria-hidden="true">#</a> 有关JS函数读取传入对象属性值时，形参与实参所带来的问题</h1><p>在JavaScript函数当中，当我们传入对象时，可以通过直接读取对象属性以获取属性值，以下为例：</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">function</span> <span class="token function">inputObj</span> <span class="token punctuation">(</span><span class="token parameter">object</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token operator">...</span><span class="token operator">...</span>
    <span class="token keyword">let</span> getValue <span class="token operator">=</span> object<span class="token punctuation">.</span>someProps<span class="token punctuation">;</span>
    <span class="token operator">...</span><span class="token operator">...</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>但是需要注意，在传入对象后使用 &quot;.&quot; 所引用的属性值必须为实参（也就是希望读取的对象的属性必须是实际的值）。</p><p>例如如下例子，在这个例子里，我们将属性值也传入函数中。当我们读取时，就不能使用以下这种方法：</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">function</span> <span class="token function">getObjAndProp</span> <span class="token punctuation">(</span><span class="token parameter">object<span class="token punctuation">,</span> prop</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token keyword">let</span> getValue <span class="token operator">=</span> object<span class="token punctuation">.</span>prop<span class="token punctuation">;</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>因为这样的方法会使 JavaScript 将 prop 解析为字符串值，并尝试读取该对象中名字为 “prop” 的参数，而不是尝试使用传入的参数，也就是实参进行读取。但很明显 props 只是形参，这使得读取会出现比较大的问题。</p><p>此时我们应该 <strong>将读取方式改为object[prop]</strong>，参照如下方法：</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">function</span> <span class="token function">getObjAndPropCorrectly</span> <span class="token punctuation">(</span><span class="token parameter">object<span class="token punctuation">,</span> prop</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token operator">...</span><span class="token operator">...</span>
    <span class="token keyword">let</span> getValue <span class="token operator">=</span> object<span class="token punctuation">[</span>prop<span class="token punctuation">]</span><span class="token punctuation">;</span>
    <span class="token operator">...</span><span class="token operator">...</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>在这种情况下，JavaScript就会将prop解析为变量而不是字符串值，解决了使用形参读取传入对象属性的问题。</p>`,10),o=[t];function c(i,r){return a(),s("div",null,o)}const d=n(p,[["render",c],["__file","Formal_Real_Para_When_Func_Get_Obj.html.vue"]]);export{d as default};
